//! Versioned dump filename conventions and ambient-TeXLive detection.
//!
//! All kernel dumps generated by `--init=plain.tex` and `--init=latex.ltx`
//! are tagged with the TeXLive release year of the ambient install:
//!
//! ```text
//! resources/dumps/plain.2025.dump.txt
//! resources/dumps/latex.2025.dump.txt
//! resources/dumps/texlive.2025.version
//! ```
//!
//! At runtime we detect the ambient year (via the `kpsewhich --version` /
//! `kpsewhich -var-value=SELFAUTOPARENT` banners, with `pdflatex --version`
//! as fallback â€” see [`detect_ambient_texlive_year`]) and pick the matching
//! dump. If no exact match exists â€” or no TeXLive is installed at all â€” we
//! fall back to the most-recent year present.
//!
//! Why versioned: `latex.dump.txt` content reflects whatever raw `latex.ltx`
//! / `expl3-code.tex` shipped with the ambient TeXLive at `--init` time.
//! Cross-loading a dump from a different TL into a different TL silently
//! diverges. Tagging by year makes the relationship explicit and lets us
//! bundle multiple TL years into a single binary (see
//! [`embedded_dumps`](crate::embedded_dumps)).

use std::path::{Path, PathBuf};
use std::sync::OnceLock;

/// Detect the ambient TeXLive release year. Returns `None` if no TeXLive
/// is installed (or detection fails for some other reason).
///
/// Strategy (ordered for one-subprocess-per-distro; see the body for the
/// spawn-cost rationale):
///   1. `kpsewhich --version` â†’ MiKTeX prints `MiKTeX YY.MM` â†’ `20YY` (TeX Live
///      has no year here and falls through).
///   2. `kpsewhich -var-value=SELFAUTOPARENT` â†’ e.g. `/usr/local/texlive/2025`. Last path
///      component, if it parses as a 4-digit year (2000..=2099), wins.
///   3. `pdflatex --version` â†’ first line typically contains `(TeX Live YYYY)`.
pub fn detect_ambient_texlive_year() -> Option<u32> {
  // Process-global memo. The ambient TeX year is a constant property of the
  // installed distribution â€” it cannot change mid-process â€” but detection is
  // called from several sites per conversion (plain/latex dump load, ini), and
  // each site spawns a probe subprocess. On MiKTeX those subprocesses are
  // ~340ms EACH (~10-25x TeX Live's), so an unmemoized detect cost ~0.7s PER
  // call site â€” the dominant Windows/MiKTeX slowdown (the "load" before the
  // first dump_reader log). Detect once. Thread-safe: the year is
  // process-level, not per-thread State.
  static AMBIENT_TEXLIVE_YEAR: OnceLock<Option<u32>> = OnceLock::new();
  *AMBIENT_TEXLIVE_YEAR.get_or_init(|| {
    // Probe order is chosen so EACH distribution resolves in a single
    // subprocess (the spawn is the whole cost â€” ~340ms on MiKTeX):
    //   1. `kpsewhich --version` banner. MiKTeX prints `MiKTeX YY.MM` on stdout
    //      â†’ `20YY`, and this is MiKTeX's ONLY single-spawn year signal
    //      (SELFAUTOPARENT is empty there, so step 2 can't help it). Resolving
    //      here saves MiKTeX the extra `pdflatex --version` spawn. TeX Live's
    //      banner is `kpathsea version 6.4.x` (no year) so it returns None â€” but
    //      only costs ~28ms on TeX Live, so the extra probe is effectively free.
    //   2. `kpsewhich -var-value=SELFAUTOPARENT` â†’ `.../texlive/2026`: TeX Live's
    //      fast path (MiKTeX already exited at step 1).
    //   3. `pdflatex --version`: last-resort fallback for exotic setups where
    //      neither kpsewhich signal carries a year.
    // Answer-identical to a SELFAUTOPARENT-first order on both distros; just
    // fewer spawns (MiKTeX: 2 â†’ 1).
    if let Some(year) = year_from_kpsewhich_version_banner() {
      return Some(year);
    }
    if let Some(year) = year_from_kpsewhich_selfautoparent() {
      return Some(year);
    }
    year_from_pdflatex_version()
  })
}

/// The ambient `kpsewhich --version` banner (full stdout), memoized for the
/// process. It is a global property of the host TeX install, and TWO consumers
/// read it â€” ambient-year detection ([`year_from_kpsewhich_version_banner`])
/// and the latex-dump staleness stamp check (`compare_stamp_to_ambient` in the
/// build.rs-generated loader) â€” so spawning `kpsewhich` once and sharing the
/// result saves a full subprocess (~340ms on MiKTeX). Returns `None` if
/// kpsewhich is absent or the call fails.
pub fn ambient_kpsewhich_version() -> Option<&'static str> {
  static BANNER: OnceLock<Option<String>> = OnceLock::new();
  BANNER
    .get_or_init(|| {
      let out = std::process::Command::new("kpsewhich")
        .arg("--version")
        .output()
        .ok()?;
      if !out.status.success() {
        return None;
      }
      String::from_utf8(out.stdout).ok()
    })
    .as_deref()
}

/// Year from the memoized `kpsewhich --version` banner. Only MiKTeX carries a
/// year here (`MiKTeX YY.MM` on stdout, e.g. `MiKTeX 25.12` â†’ 2025); TeX Live
/// prints `kpathsea version 6.4.x` (no year) and so returns `None`, deferring
/// to SELFAUTOPARENT. Reuses [`parse_year_from_version_banner`] â€” the same
/// extractor as the `pdflatex --version` fallback, which also handles a
/// leading MiKTeX "check for updates" warning line without a false match.
fn year_from_kpsewhich_version_banner() -> Option<u32> {
  parse_year_from_version_banner(ambient_kpsewhich_version()?)
}

fn year_from_kpsewhich_selfautoparent() -> Option<u32> {
  let out = std::process::Command::new("kpsewhich")
    .arg("-var-value=SELFAUTOPARENT")
    .output()
    .ok()?;
  if !out.status.success() {
    return None;
  }
  let s = String::from_utf8(out.stdout).ok()?;
  let trimmed = s.trim();
  let last = Path::new(trimmed).file_name()?.to_str()?;
  parse_year_str(last)
}

fn year_from_pdflatex_version() -> Option<u32> {
  let out = std::process::Command::new("pdflatex")
    .arg("--version")
    .output()
    .ok()?;
  if !out.status.success() {
    return None;
  }
  let s = String::from_utf8(out.stdout).ok()?;
  parse_year_from_version_banner(&s)
}

/// Extract a TL-equivalent year from a `pdflatex --version` banner.
///
///   - TeX Live: first lines contain `(TeX Live YYYY)`.
///   - MiKTeX: no TL year exists anywhere (and `SELFAUTOPARENT` is EMPTY on
///     MiKTeX, so detection lands here). The banner reads
///     `MiKTeX-pdfTeX 4.23 (MiKTeX 25.12)`; MiKTeX is a rolling release
///     whose `YY.MM` package snapshot tracks the same-year TeX Live, so map
///     `MiKTeX YY.*` â†’ `20YY` and let dump resolution do its usual
///     nearest/most-recent fallback if that exact year isn't bundled.
fn parse_year_from_version_banner(s: &str) -> Option<u32> {
  for line in s.lines().take(3) {
    if let Some(idx) = line.find("TeX Live ") {
      let tail = &line[idx + "TeX Live ".len()..];
      let candidate: String = tail.chars().take(4).collect();
      if let Some(y) = parse_year_str(&candidate) {
        return Some(y);
      }
    }
    // Match the parenthesized distro stamp, not the product prefix: the
    // banner starts `MiKTeX-pdfTeX 4.23 (MiKTeX 25.12)` and only the
    // second occurrence carries the version.
    if let Some(idx) = line.find("MiKTeX ") {
      let tail = &line[idx + "MiKTeX ".len()..];
      let digits: String = tail.chars().take_while(char::is_ascii_digit).collect();
      if digits.len() == 2
        && let Ok(yy) = digits.parse::<u32>()
        && (20..=99).contains(&yy)
      {
        return Some(2000 + yy);
      }
    }
  }
  None
}

fn parse_year_str(s: &str) -> Option<u32> {
  // Accept a trailing non-digit suffix: MacTeX/BasicTeX name their TL root
  // with one (e.g. `/usr/local/texlive/2026basic`), so SELFAUTOPARENT's
  // final component carries the year + "basic". Parse the leading digit
  // run; a string that doesn't START with the year (e.g. "texlive") still
  // fails over to the `pdflatex --version` detection.
  let digits = &s[..s.find(|c: char| !c.is_ascii_digit()).unwrap_or(s.len())];
  let y: u32 = digits.parse().ok()?;
  if (2000..=2099).contains(&y) {
    Some(y)
  } else {
    None
  }
}

/// Versioned filename for a kernel dump, e.g.
/// `dump_filename("plain", 2025) == "plain.2025.dump.txt"`.
pub fn dump_filename(kind: &str, year: u32) -> String { format!("{}.{}.dump.txt", kind, year) }

/// One-shot stderr banner emitted by the `LoadFormat` branches in
/// `tex.rs` / `latex.rs` when NO precompiled kernel dump is available
/// and the engine falls back to the raw `latex.ltx` + `expl3-code.tex`
/// load path.
///
/// Why this exists: the raw-load path hits known raw-load-ONLY cascades
/// (the `expl3-code.tex` L33075 codepoint dangling-group and the
/// `\@expl@pop@filename@@` expl-status desync) that the dump avoids. On
/// expl3-heavy arXiv articles this inflates per-paper error counts by
/// ~1000Ă— (2112.11932: 1 â†’ 1003; 2110.10227: 4 â†’ 102), which previously
/// masqueraded as a Rust parity gap when it was really a missing-dump
/// SETUP error (`resources/dumps/` not populated â€” run
/// `tools/make_formats.sh`). The dump is a required kernel piece for
/// canvas/parity work, so its absence must never be silent.
///
/// Fires at most once per process (shared `Once`), and is a plain stderr
/// line â€” NOT an `Error:`/`Fatal:` (those are reserved for the per-paper
/// conversion log and would corrupt canvas error counts).
pub fn warn_degraded_no_dump() {
  static WARNED: std::sync::Once = std::sync::Once::new();
  WARNED.call_once(|| {
    let year = detect_ambient_texlive_year()
      .map(|y| y.to_string())
      .unwrap_or_else(|| "unknown".into());
    eprintln!(
      "[latexml-oxide] WARNING: no precompiled kernel dump found (TL{year}); \
       running in DEGRADED raw-load mode. Conversions will show many spurious \
       errors (expl3 catcode/group cascades). Build the dump with \
       `tools/make_formats.sh` before canvas/parity runs. (Set \
       LATEXML_NODUMP=1 to silence this if the raw path is intentional.)"
    );
  });
}

/// Versioned filename for the texlive stamp, e.g.
/// `version_filename(2025) == "texlive.2025.version"`.
pub fn version_filename(year: u32) -> String { format!("texlive.{}.version", year) }

/// Reverse of [`dump_filename`]: extract the year tag from a versioned
/// dump filename. Returns `None` for un-versioned legacy names.
pub fn parse_year_from_dump_filename(name: &str, kind: &str) -> Option<u32> {
  let prefix = format!("{}.", kind);
  let rest = name.strip_prefix(&prefix)?;
  let year_str = rest.strip_suffix(".dump.txt")?;
  parse_year_str(year_str)
}

/// All TL years for which a `<kind>.YYYY.dump.txt` file exists in `dir`,
/// sorted descending (most-recent first).
pub fn available_years_in_dir(dir: &Path, kind: &str) -> Vec<u32> {
  let mut years = Vec::new();
  let Ok(entries) = std::fs::read_dir(dir) else {
    return years;
  };
  for entry in entries.flatten() {
    let name = entry.file_name();
    let Some(name_str) = name.to_str() else {
      continue;
    };
    if let Some(y) = parse_year_from_dump_filename(name_str, kind) {
      years.push(y);
    }
  }
  years.sort_unstable_by(|a, b| b.cmp(a));
  years.dedup();
  years
}

/// Pick the best dump in `dir` for the given `kind` (`"plain"` /
/// `"latex"`):
///   - if `prefer` is `Some(y)` and `<kind>.y.dump.txt` exists, use it;
///   - else use the most-recent year present;
///   - else `None`.
pub fn resolve_versioned_in_dir(
  dir: &Path,
  kind: &str,
  prefer: Option<u32>,
) -> Option<(PathBuf, u32)> {
  if let Some(y) = prefer {
    let p = dir.join(dump_filename(kind, y));
    if p.is_file() {
      return Some((p, y));
    }
  }
  let years = available_years_in_dir(dir, kind);
  let chosen = years.first().copied()?;
  Some((dir.join(dump_filename(kind, chosen)), chosen))
}

/// Sibling stamp file for a dump path â€” e.g. `texlive.2025.version`
/// next to `latex.2025.dump.txt`.
pub fn stamp_path_for_dump(dump_path: &Path, year: u32) -> Option<PathBuf> {
  Some(dump_path.parent()?.join(version_filename(year)))
}

#[cfg(test)]
mod year_parse_tests {
  use super::{parse_year_from_version_banner, parse_year_str};

  #[test]
  fn texlive_banner() {
    assert_eq!(
      parse_year_from_version_banner("pdfTeX 3.141592653-2.6-1.40.29 (TeX Live 2026)"),
      Some(2026)
    );
    // Homebrew stamp variant.
    assert_eq!(
      parse_year_from_version_banner("pdfTeX 3.14 (TeX Live 2026/Homebrew)"),
      Some(2026)
    );
  }

  #[test]
  fn miktex_banner_maps_rolling_version_to_year() {
    // Verbatim from MiKTeX 25.12 on Windows (probe 2026-07-12); note
    // SELFAUTOPARENT is empty on MiKTeX, so this arm is the only signal.
    assert_eq!(
      parse_year_from_version_banner("MiKTeX-pdfTeX 4.23 (MiKTeX 25.12)"),
      Some(2025)
    );
  }

  #[test]
  fn unknown_banner_rejected() {
    assert_eq!(
      parse_year_from_version_banner("pdfTeX 3.14 (Web2C 2026)"),
      None
    );
    // A hypothetical 3-digit MiKTeX version must not parse as a year.
    assert_eq!(parse_year_from_version_banner("(MiKTeX 125.1)"), None);
  }

  #[test]
  fn vanilla_tl_year() {
    assert_eq!(parse_year_str("2025"), Some(2025));
    assert_eq!(parse_year_str("2026"), Some(2026));
  }

  #[test]
  fn basictex_suffixed_year() {
    // MacTeX/BasicTeX layout: /usr/local/texlive/2026basic
    assert_eq!(parse_year_str("2026basic"), Some(2026));
  }

  #[test]
  fn non_year_components_rejected() {
    assert_eq!(parse_year_str("texlive"), None); // brew Cellar layout
    assert_eq!(parse_year_str("basic2026"), None);
    assert_eq!(parse_year_str(""), None);
    assert_eq!(parse_year_str("1999"), None); // outside the sane range
    assert_eq!(parse_year_str("20269"), None); // 5-digit run is not a year
  }
}
